import{_ as t,o as a,c as r,a3 as s}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Tenant RBAC — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant RBAC — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/tenant-rbac"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant RBAC — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/tenant-rbac"}]]},"headers":[],"relativePath":"user-guide/tenant-rbac.md","filePath":"user-guide/tenant-rbac.md","lastUpdated":1784905729000}'),o={name:"user-guide/tenant-rbac.md"};function n(d,e,i,l,c,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="tenant-rbac-—-user-guide" tabindex="-1">Tenant RBAC — User Guide <a class="header-anchor" href="#tenant-rbac-—-user-guide" aria-label="Permalink to &quot;Tenant RBAC — User Guide&quot;">​</a></h1><p>Manage who can access your workspace and what they can do.</p><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><p>Open <strong>Administration → Users</strong>.</p><table tabindex="0"><thead><tr><th>Action</th><th>How</th></tr></thead><tbody><tr><td>View</td><td>Search, filter by status, open a row</td></tr><tr><td>Create</td><td><strong>New user</strong> → name, email, password, roles; optionally <strong>Exclude from lead assignment</strong> and <strong>Receive all-users daily summary</strong></td></tr><tr><td>Edit</td><td>Row menu → <strong>Edit</strong> → update details, roles, lead-assignment exclusion, and all-users daily summary</td></tr><tr><td>Activate / Deactivate</td><td>Suspend / Unsuspend (when available)</td></tr><tr><td>Reset password</td><td>Row menu → change password</td></tr><tr><td>Resend verification</td><td>Row menu → <strong>Resend verification</strong> (unverified users; requires <code>users.verify</code>)</td></tr><tr><td>Mark email verified</td><td>Row menu → <strong>Mark as verified</strong> when the member never received the email (requires <code>users.verify</code>)</td></tr><tr><td>Delete</td><td>Row menu → <strong>Delete</strong> (if your role allows it)</td></tr></tbody></table><p><strong>Receive all-users daily summary</strong> grants a workspace-wide view of open leads, tasks, and meetings in the daily team email. Prefer Owner / Admin accounts. That user receives the team rollup <strong>instead of</strong> a personal summary.</p><p>Each person belongs only to <strong>this</strong> workspace. They cannot see users from other workspaces.</p><p>Roles control what the user can do. Prefer assigning roles rather than asking for one-off exceptions.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><p>Open <strong>Administration → Roles</strong>.</p><table tabindex="0"><thead><tr><th>Action</th><th>How</th></tr></thead><tbody><tr><td>Create</td><td><strong>New role</strong> → name</td></tr><tr><td>Edit</td><td>Row menu → <strong>Edit</strong> → toggle permissions</td></tr><tr><td>Clone</td><td>Row menu → <strong>Clone</strong></td></tr><tr><td>Delete</td><td>Row menu → <strong>Delete</strong> (not allowed for Owner / system defaults)</td></tr><tr><td>Matrix</td><td><strong>Permissions matrix</strong> — read-only overview by module group</td></tr></tbody></table><p>Example roles you might create: Sales Manager, Sales Agent, Finance, Support. Defaults often include Owner (<code>superadmin</code>), Administrator, Manager, and Staff.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Permissions are checked actions such as <code>users.list</code> or <code>leads.create</code>.</p><ul><li>Granted to <strong>roles</strong>, not directly to users (standard setup).</li><li>Grouped by area (Users, Roles, Settings, Leads, Tasks, Communication Templates, …) when editing a role.</li><li>The permissions list / matrix is read-only; change access by editing roles.</li></ul><h2 id="modules-and-access" tabindex="-1">Modules and access <a class="header-anchor" href="#modules-and-access" aria-label="Permalink to &quot;Modules and access&quot;">​</a></h2><p>Two checks apply to product areas (e.g. Leads):</p><ol><li>Your workspace must <strong>own</strong> (subscribe to) the module.</li><li>Your role must include the needed permission.</li></ol><p>If the workspace does not own the module, nobody can use it—even with permissions assigned.</p><h2 id="owner" tabindex="-1">Owner <a class="header-anchor" href="#owner" aria-label="Permalink to &quot;Owner&quot;">​</a></h2><p>The person who registered the workspace is the Owner. They have full workspace access by default, can add administrators, and manage users, roles, and settings. They do <strong>not</strong> access the Central (platform) admin console.</p>',21)])])}const h=t(o,[["render",n]]);export{p as __pageData,h as default};
